INSERT INTO `noticias` (`idNoticia`, `tituloNoticia`, `descripcionNoticia`, `fechaCreacionNoticia`, `fechaPublicacionNoticia`, `urlImagenNoticia`, `estadoNoticia`, `idAutorNoticia`) VALUES
(20, 'El telescopio James Webb revela nuevas imágenes sin precedentes de la formación de estrellas', '<p>El telescopio espacial James Webb Space Telescope continúa revolucionando la astronomía con la publicación de nuevas imágenes de la región de formación estelar conocida como Nebulosa de Orión, ubicada a unos 1.350 años luz de la Tierra.</p><p>Las observaciones, realizadas en el espectro infrarrojo, permiten ver a través de densas nubes de polvo cósmico, revelando detalles nunca antes observados en el nacimiento de estrellas y sistemas planetarios.</p><p>Los científicos lograron identificar discos protoplanetarios —estructuras de gas y polvo donde se forman planetas— alrededor de estrellas jóvenes, lo que ayuda a comprender mejor cómo se originan sistemas como nuestro propio sistema solar.</p><p>Además, las imágenes muestran complejas interacciones entre radiación estelar y el entorno interestelar, aportando nuevas pistas sobre cómo influyen las estrellas masivas en la evolución de su entorno.</p><p>Según los investigadores, estos descubrimientos permiten reconstruir con mayor precisión las primeras etapas de la formación estelar, un proceso clave para entender la evolución del universo.</p><p>Desde su lanzamiento, el James Webb se ha consolidado como una de las herramientas más importantes de la astronomía moderna, superando ampliamente las capacidades de telescopios anteriores como el Hubble Space Telescope.</p>', '2026-04-15 20:23:44', '2026-04-16 13:30:02', '1776295486_6b72c052b2a8ba3c1633.jpg', 4, 1),
(21, 'Histórica misión logra traer muestras de un asteroide a la Tierra', '<p>La misión espacial OSIRIS-REx de la NASA logró con éxito traer a la Tierra muestras del asteroide Bennu, en un hito clave para la exploración espacial y el estudio del origen del sistema solar.</p><p>La cápsula con el material recolectado aterrizó en el desierto de Utah, en Estados Unidos, tras un viaje de más de siete años. Los científicos estiman que se recuperaron alrededor de 250 gramos de polvo y rocas del asteroide.</p><p>Estas muestras son especialmente valiosas porque Bennu es un asteroide primitivo, rico en carbono, lo que podría aportar información sobre los compuestos orgánicos que dieron origen a la vida en la Tierra.</p><p>Además, el estudio de este tipo de cuerpos celestes también ayuda a comprender mejor los riesgos de impacto de asteroides y cómo podrían desviarse en el futuro.</p><p>Los primeros análisis ya detectaron la presencia de agua y moléculas orgánicas en el material recolectado, reforzando la teoría de que los ingredientes básicos para la vida podrían ser comunes en el universo.</p><p>Tras completar esta misión, la nave OSIRIS-REx continuará su viaje hacia un nuevo objetivo, el asteroide Apophis, en una misión extendida que seguirá aportando datos clave para la ciencia. </p>', '2026-04-15 20:32:28', '2026-04-15 20:59:52', '1776297570_ad5e14edd949a15d96fe.jpg', 4, 1),
(22, 'Nueva regulación europea obliga a empresas tecnológicas a reforzar la protección de datos', '<p>La Unión Europea anunció la implementación de nuevas normativas digitales que exigirán a grandes empresas tecnológicas mejorar la protección de datos personales y aumentar la transparencia en el uso de algoritmos.</p><p>La legislación, conocida como Ley de Servicios Digitales (DSA, por sus siglas en inglés), apunta especialmente a plataformas como Meta, Google y TikTok.</p><p>Entre las medidas más importantes, se incluye la obligación de:</p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Explicar cómo funcionan los algoritmos de recomendación</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Eliminar contenido ilegal con mayor rapidez</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Proteger especialmente a menores de edad</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Permitir a los usuarios controlar mejor su información personal</li></ol><p>Las empresas que no cumplan con estas reglas podrían enfrentar multas de hasta el 6% de su facturación global anual.</p><p>Expertos en tecnología consideran que esta normativa podría marcar un antes y un después en la regulación de internet, y servir como modelo para otros países.</p><p>Por su parte, algunas compañías han expresado preocupación por los costos de implementación, aunque también reconocen que la regulación podría ayudar a mejorar la confianza de los usuarios.</p>', '2026-04-15 21:18:24', '2026-04-15 21:18:45', NULL, 4, 4),
(23, 'Hallazgo histórico: captan al “pez fantasma”, el animal jamás visto vivo ', '<p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Pese a que la ciencia avanzó a tal punto de poder descubrir casi todos los&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">seres vivos</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;que habitan en nuestro planeta, hay algunos rincones del globo que aún se muestran desconocidos a la espera de que la tecnología permita su adecuada y segura exploración. Un ejemplo son las profundidades marinas, donde diversas especies aún se mantienen ocultas al ojo humano.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Sin embargo, una de ellas se ha revelado de manera reciente y a pesar de que había miles de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://www.cronista.com/informacion-gral/alerta-en-argentina-la-nasa-advirtio-que-una-anomalia-esta-creciendo-y-podria-traer-graves-consecuencias/\" rel=\"noopener noreferrer\" target=\"_blank\">indicios científicos</a></strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;de su existencia, esta fue la primera que pudo ser avistada tras despertar el interés de distintos&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">investigadores</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;durante los últimos años.</span></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">¿Cuál es la criatura marina que descubrieron en el Pacífico?</span></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Un&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">equipo de científicos</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;fueron testigos directos de la presencia del zifio de Ginkgo o zifio japonés, un animal realmente escurridizo para los especialistas en&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">biología marina</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Muchos de los expertos sabían de su existencia debido a las diferentes señales que numerosos ejemplares dejaban de su presencia. No obstante, jamás se había observado ninguno de ellos de primera mano, dejando un ambiente de misticismo a su alrededor.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Los&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">investigadores&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">fueron testigos directos de la presencia de estos extraños cetáceos mientras se hallaban a bordo de una embarcación frente a las costas de Baja California, México.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El histórico evento fue registrado en la prestigiosa revista científica&nbsp;</span><em style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Marine Mammal Science</em><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;y permite aportar claridad a uno de los misterios más perseguidos por la comunidad internacional.</span></p><p><span style=\"color: rgb(38, 38, 38); background-color: rgb(242, 242, 242);\"><img src=\"https://img-s-msn-com.akamaized.net/tenant/amp/entityid/AA1RJcnu.img?w=768&amp;h=512&amp;m=6\" alt=\"El hallazgo de los científicos en el Pacífico fue esta criatura marina.\"></span></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">¿Cómo fue la investigación que encontró a este animal?</span></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Los primeros signos de la existencia del&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">zifio de Ginkgo</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;fueron detectados a través de unas grabaciones realizadas en el Pacífico Norte, que captaron un pulso ecolocalización extraño, al que le dieron el nombre de BW43.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">A pesar de que los sonidos parecían surgir de un&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">zifio japonés</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, los investigadores no conseguían descifrar a qué especie pertenecía de manera exacta.Los análisis posteriores confirmaron que se trataba de esa criatura misteriosa que, hasta el momento, solo se había podido observar en forma de cadáveres varados.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">En esta línea, no fue hasta su observación que se pudieron captar imágenes del desconocido animal, además de obtener&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">ADN&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">de uno de los muchos ejemplares que emergieron discretamente el día del avistamiento.</span></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">¿Cómo son los zifios japoneses?</span></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Los zifios pasan gran parte de su tiempo vital sumergidos en las profundidades más abruptas del océano. Sus salidas a la superficie acuática son escasas y poco notables, evitando su aparición frente a cualquier tipo de movimiento sospechoso para ellos. Su naturaleza los convierte en uno de los&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">mamíferos marinos&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">más complejos de analizar.</span></p><p><span style=\"color: rgb(38, 38, 38); background-color: rgb(242, 242, 242);\"><img src=\"https://img-s-msn-com.akamaized.net/tenant/amp/entityid/AA1RJ2wm.img?w=768&amp;h=555&amp;m=6\" alt=\"Esta criatura nunca se pudo ver, porque suele habitar el fondo del mar.\"></span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El zifio japonés, también conocido como zifio de Ginkgo o Mesoplodon ginkgodens, es una especie de cetáceo odontoceto que habita en&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">aguas tropicales y templadas del Océano Pacífico</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Se trata de uno de los mamíferos marinos menos conocidos debido a su vida en grandes profundidades. Se le llama así porque sus primeros registros de ejemplares encontrados se ubican en&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Japón</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Respecto a su morfología, tiene un hocico pronunciado y aletas pequeñas. Los machos adultos desarrollan uno o dos colmillos que sobresalen en la mandíbula inferior. Sus&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">colores&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">van desde el gris claro hasta el marrón rojizo y tiene manchas en la cabeza, así como alrededor del hocico.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Este animal&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">suele alimentarse de otros cefalópodos&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">y pasan la mayor parte del tiempo en las profundidades marinas. Para nadar y ubicarse, utilizan un sofisticado sistema de ecolocalización que también les permite encontrar presas en la oscuridad.</span></p><p><br></p>', '2026-04-15 21:21:33', '2026-04-15 21:21:33', NULL, 6, 4),
(24, 'Tierra del Fuego pidió explicaciones a Uruguay por un vuelo británico a las Malvinas', '<p>La Argentina y Uruguay están en una disputa diplomática por causa de un avión militar británico que habría volado desde las Islas Malvinas hasta aterrizar en el aeropuerto de Maldonado, en el país vecino. Andrés Dachary, secretario de Malvinas, Antártida, Islas del Atlántico Sur y Asuntos Internacionales de la provincia de Tierra del Fuego publicó un extenso mensaje de protesta por la red social \"X\". Allí relata la autorización que el gobierno de Uruguay le habría dado a un avión militar británico para que volara desde las Islas Malvinas hasta el aeropuerto de Carrasco en el vecino país.</p><p>El reclamo formaliza un reclamo porque la nave es militar, habría salido de suelo argentino ocupado ilegítimamente por un país extranjero y, en su trayecto hasta Uruguay, voló por el espacio aéreo nacional. En su parte más significativa, el mensaje dice que la aeronave, un Airbus A400M , habría apagado su transponder, dispositivo electrónico que permite ubicar a la nave en los radares.</p><p><br></p><p><u>El comunicado del Secretario de Malvinas de Tierra del Fuego</u></p><p><br></p><p>\"Desde el Gobierno de Tierra del Fuego hemos intervenido formalmente ante el accionar de una aeronave militar Airbus A400M del Reino Unido que operó entre Montevideo y nuestras Islas #Malvinas. Según versiones de público conocimiento, el vuelo habría apagado su transponder volando sin autorización sobre espacio aéreo argentino\".</p><p><br></p><p>\"Ante la gravedad institucional de estos hechos, y frente a la información de que la aeronave habría reingresado al aeropuerto de Carrasco, remitimos una nota formal al Embajador de la @UruEnArgentina solicitando información y precisiones sobre su itinerario, autorizaciones y situación actual\".</p><p>\"Del mismo modo, exigimos a la #ANAC que informe si existen registros, trazas de radar o reportes de tránsito aéreo que permitan esclarecer lo ocurrido. La seguridad operacional, la integridad territorial y el pleno respeto de nuestra soberanía no admiten silencio ni pasividad. Desde la Provincia de Tierra del Fuego, Antártida e Islas del Atlántico Sur vamos a impulsar todas las acciones institucionales que correspondan para resguardar los intereses de nuestra Provincia y de la República Argentina\".</p><p><br></p><p>Uruguay ha tenido históricamente una serie de disputas con la Argentina por autorizar barcos y aviones británicos a operar en su territorio desde o hacia Malvinas. En este caso, no parece que se haya tratado de una emergencia que requiere una ayuda innegable, sino un vuelo \"normal\" que el país oriental autorizó.</p>', '2026-04-16 13:20:29', '2026-04-16 13:20:37', '1776356429_d06cb6ff3bfe9bbc2ea4.jpg', 4, 4),
(25, 'Fósil confirma que el adorable carpincho sí habitó en Chile', '<p>El capibara (Hydrochoerus hydrochaeris) –también conocido como carpincho, chigüire, ronsoco o chigüiro–, el roedor más grande y pesado de nuestro planeta, vive un momento de gloria global.</p><p>Desde 2020, su presencia en TikTok e Instagram lo ha convertido en un fenómeno viral que ha impulsado desde juguetes y canciones hasta su adopción como mascota en países como Rusia, China y Canadá.</p><p>Este simpático mamífero semiacuático habita en toda Sudamérica, menos en Chile. Pero ahora, una investigación publicada en el Journal of South American Earth Sciences revela que el capibara sí habitó territorio chileno, pero lo hizo hace 4,5 millones de años.</p><p><u>Restos encontrados durante excavaciones para un parque eólico</u></p><p>El descubrimiento ocurrió en la comuna de Renaico, región de La Araucanía (centro-sur), durante las excavaciones realizadas por la consultora paleontológica THERIUM en el marco de la construcción de un parque eólico.</p><p>El equipo \"se dio cuenta, por la forma que tenía este diente, de que eran muy posiblemente los de un roedor grande. Hoy en día, los capibaras son los roedores más grandes que viven en el planeta, pero en el pasado hubo también otros roedores de gran tamaño\", explica la autora principal, Karina Buldrini, a la emisora chilena T13.</p><p><u>Evidencia anatómica de gigantes prehistóricos</u></p><p>El hallazgo incluye un molar, incisivos, fragmentos de fémur y parte de una pelvis. Estos restos fósiles expanden la distribución del género Phugatherium al oeste de la cordillera de los Andes.</p><p>\"Estos hallazgos constituyen la primera prueba anatómica de la presencia de capibaras en Chile y el primer registro neogénico de mamíferos continentales en la Depresión Central chilena\", escriben los autores.</p><p>Este ancestro del capibara era mucho más grande que el actual. Christiane Denys, profesora del Museo Nacional de Historia Natural (MNHN) de Francia, detalla en un artículo de 2025 en The Conversation que estos \"capibaras gigantes\" podían medir dos metros y pesar hasta 300 kg, similar a un tapir.</p><p><u>El antiguo paisaje de la región de La Araucanía</u></p><p>El capibara actual es un herbívoro que prospera en humedales y zonas tropicales. El fósil de Renaico, junto a restos de un litopterno —animal herbívoro extinto— encontrado en las cercanías, podría entregar información reveladora sobre cómo era el paisaje de esa zona en el pasado.</p><p>Este descubrimiento \"sugiere que la localidad de Renaico presentaba un paisaje heterogéneo que combinaba humedales y hábitats abiertos\", transformando la comprensión de un ecosistema que hoy es predominantemente agrícola.</p>', '2026-04-16 13:22:42', '2026-04-16 13:23:04', NULL, 4, 4),
(26, 'Hallazgo histórico: un grupo de científicos encontró el animal más longevo del planeta Tierra', '<p>Un grupo de científicos identificó un tiburón de Groenlandia que podría tener cerca de 399 años, lo que lo convertiría en uno de los animales más longevos del planeta Tierra.</p><p>La noticia se dio luego de que se analizaran 28 tiburones que fueron capturados de manera incidental por pescadores.</p><p><u>Hallazgo histórico para la ciencia</u></p><p>En la investigación publicada en la revista Science, se analizaron 28 tiburones de Groenlandia de distinta edad, que habita en aguas frías y profundas del océano Ártico.</p><p>El estudio arrojó estos resultados:</p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>La edad promedio de los ejemplares fue de, al menos, 272 años.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>El tiburón más grande, de más de 5 metros, habría nacido alrededor de 1627, es decir, hace unos 399 años.</li></ol><p>Los científicos llegaron a la conclusión de que esta longevidad fuera de lo común se debe a una combinación de factores:</p><ol><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Crecimiento lento: el tiburón crece alrededor de 1 centímetro por año.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Madurez sexual tardía: estos tiburones alcanzan la adultez recién a los 150 años.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Metabolismo: es bajo debido a su adaptación a las bajas temperaturas cercanas al congelamiento.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Hábitat profundo: se trata de lugares estables que pueden superar los 2.000 metros de profundidad.</li><li data-list=\"bullet\"><span class=\"ql-ui\" contenteditable=\"false\"></span>Mecanismos genéticos: pueden reparar el ADN que contribuye a resistir algunas enfermedades.</li></ol><p><u>Cuáles son las características del tiburón de Groenlandia</u></p><p>Se trata de una especie que puede alcanzar hasta 7 metros de largo y pesar más de 1.000 kilos. Es capaz de nadar a 2km/h, es decir, mucho más lento que otras especies de tiburones.</p><p>Su alimentación es a base de focas, peces, calamares y restos orgánicos y debido a su adaptación a temperaturas extremas es capaz de resistir gracias a su metabolismo lento.</p>', '2026-04-16 13:25:21', '2026-04-16 13:39:33', '1776356745_bdf4b5e0426925413404.jpg', 4, 4),
(27, 'Argentina hace historia con el regreso de un mamífero en peligro de extinción', '<p>Un animal que estaba extinto hace 110 años en esta región de la Argentina volvió a habitar estas tierras tras un largo proceso que llevó años para lograr su reintroducción.</p><p>Se trata del guanaco, una especie que logró volver al Chaco después de 110 años, un acontecimiento que marca un hito en la conservación argentina.</p><p>El operativo, realizado por la Fundación Rewilding Argentina junto a la Provincia y la Administración de Parques Nacionales, logró reintroducir a esta especie en el Parque Nacional El Impenetrable, donde había desaparecido hace más de un siglo.</p><p><u>¿Por qué es importante el regreso del guanaco a Chaco?</u></p><p>La extinción regional del guanaco dejó un vacío ecológico enorme. Este animal es el mayor herbívoro de Sudamérica y cumple un rol clave en la dinámica del ecosistema.</p><p>Su presencia ayuda a mantener la vegetación y a sostener la cadena alimentaria, lo que favorece la biodiversidad en el monte chaqueño.</p><p><u>¿Cómo fue el operativo para traerlo de vuelta?</u></p><p>El regreso del guanaco no fue casual. El equipo trabajó durante meses en la Patagonia para diseñar un plan seguro y eficiente. La técnica elegida fue un arreo controlado con cuatro motos en forma de “V”, que guiaron a los animales hacia un embudo y luego a la manga del tráiler.</p><p>Todo se hizo en la estepa del noroeste de Santa Cruz, dentro del Parque Patagonia. Cada paso se planificó para cuidar el bienestar de los animales: se respetaron los grupos familiares, se evitó separar crías y se redujo el estrés durante el traslado.</p><p>Después del arreo, los guanacos viajaron por tierra hasta el Chaco, en un operativo sin precedentes en la historia de la fauna argentina.</p><p><u>¿Cuáles son los pasos a seguir?</u></p><p>En los próximos días, la Fundación Rewilding Argentina dará detalles sobre el traslado y los desafíos que enfrentaron para que el guanaco vuelva a formar parte del paisaje chaqueño.</p><p>Este proyecto busca restaurar el equilibrio ecológico y abrir una nueva etapa para la conservación en el país.</p><p>A su vez, hace unas semanas apareció un mamífero extinto localmente, un acontecimiento que renueva las esperanzas para una de las especies más amenazadas de Sudamérica.</p><p>El hito corona más de ocho años de trabajo sostenido dedicado a la conservación de este carnívoro acuático icónico.</p><p>Se trata de una familia entera de nutria gigante que fue liberada en el Gran Parque Iberá, en el corazón de Corrientes.</p>', '2026-04-16 13:29:06', NULL, NULL, 3, 1),
(28, 'Las razas de perros que viven más años', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(38, 38, 38);\">Existen numerosos factores que inciden en cuánto tiempo vivirá un perro, desde su alimentación y su cuidado general hasta otros más determinantes como la raza y su tamaño. Como normal general, los perros pequeños suelen vivir más años que los grandes. </span></p>', '2026-04-16 13:38:29', NULL, NULL, 3, 1),
(29, 'Alerta por chagas', '<p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El jugo artesanal de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://viapais.com.ar/cordoba/el-rincon-de-cordoba-que-vende-acai-la-fruta-de-brasil-llena-de-antioxidantes/\" rel=\"noopener noreferrer\" target=\"_blank\">açaí</a></strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, elaborado a partir del</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;fruto de la palmera Euterpe oleracea</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;que crece de forma silvestre en el</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;norte de Brasil,</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;podría estar vinculado a una de las principales vías de transmisión del&nbsp;</span><em style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Trypanosoma cruzi</em><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, el parásito responsable del&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">mal de&nbsp;</strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://viapais.com.ar/salud/chagas-una-enfermedad-silenciosa-que-alcanza-1600000-infectados-en-la-argentina/\" rel=\"noopener noreferrer\" target=\"_blank\">Chagas</a></strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">.</strong></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Así lo sugieren dos investigaciones recientes llevadas adelante por científicos brasileños, cuyos resultados fueron difundidos en un artículo publicado por el sitio especializado en noticias científicas&nbsp;</span><em style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Scidev.net.</em></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El origen del posible contagio en el açaí</span></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">La enfermedad de Chagas&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">se transmite principalmente a través de la&nbsp;</strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://viapais.com.ar/mendoza/296396-alerta-aparecieron-vinchucas-en-viviendas-del-gran-mendoza/\" rel=\"noopener noreferrer\" target=\"_blank\">vinchuca</a></strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">,</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;un insecto que actúa como vector del parásito.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">De acuerdo con los estudios, la infección asociada al consumo de açaí podría producirse de manera accidental cuando&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">el insecto, o sus heces contaminadas, es triturado junto con el fruto durante el procesamiento en licuadoras o equipos artesanales.</strong></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El contacto entre el insecto y el fruto puede darse en distintas etapas de la cadena de producción, especialmente durante su recolección y almacenamiento.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">En muchos casos, los recolectores conservan el açaí en cestos abiertos, donde el proceso de fermentación genera dióxido de carbono, un factor que atrae a la vinchuca y favorece el contacto con el fruto.</span></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Las investigaciones que revelan el riesgo oculto en el açaí artesanal</span></h2><p><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Primer estudio</strong></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Una investigación publicada en la revista</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://wwwnc.cdc.gov/eid/\" rel=\"noopener noreferrer\" target=\"_blank\">&nbsp;Emerging Infectious Diseases&nbsp;</a></strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">detectó que diez personas de las ciudades de Manaus y Lábrea&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">presentaban infección con las mismas variantes del&nbsp;</strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://viapais.com.ar/cordoba/alerta-en-cordoba-por-nuevos-casos-de-triquinosis-las-zonas-afectadas/\" rel=\"noopener noreferrer\" target=\"_blank\">parásito&nbsp;</a></strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">halladas en el jugo de açaí&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">que habían consumido días antes, elaborado de forma artesanal.</span></p><p><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">“Los hallazgos refuerzan la hipótesis de que en la región amazónica el jugo de açaí preparado artesanalmente es una de las fuentes de infección por el parásito”,</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;señaló Marcus Lacerda, de la Fundación de Medicina Tropical de Manaus.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Para arribar a esta conclusión, los científicos analizaron muestras de sangre de los pacientes y del jugo ingerido, comprobando</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;la presencia de ADN del parásito en ambos casos.</strong></p><p><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Segundo estudio</strong></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Otro trabajo científico, publicado en&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://memorias.ioc.fiocruz.br/\" rel=\"noopener noreferrer\" target=\"_blank\">Memórias do Instituto Oswaldo Cruz,</a></strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">observó que el incremento de casos de mal de Chagas en el estado de Pará, uno de los mayores consumidores de açaí en Brasil, coincide con la temporada de cosecha del fruto, entre agosto y diciembre.</span></p><p><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">“La evaluación de los números absolutos de casos confirmados sugiere que la infección por vía oral aumentó a lo largo del período, diferenciándose de lo registrado para las vías de transmisión vectorial u otras”,</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;explicó a SciDev.Net Juliana de Meis, investigadora del Instituto Oswaldo Cruz (Fiocruz), en Río de Janeiro.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">La especialista agregó que el açaí es ampliamente consumido en todo Brasil, especialmente en el norte del país, donde su preparación artesanal sigue siendo frecuente pese a su regulación desde 2012. En cambio, los jugos destinados a otras regiones o a la exportación sí pasan por procesos de pasteurización.</span></p>', '2026-04-20 18:09:53', NULL, '1776719393_adeff7b4aa2a19b8689e.jpg', 6, 1),
(30, 'Gigantes de oro: Las pepitas más grandes encontradas en la historia', '<p><span style=\"background-color: rgb(255, 255, 255); color: rgb(38, 38, 38);\">Hace más de 150 años, un extraordinario evento&nbsp;en Moliagul (Australia)&nbsp;cambió para siempre la historia de la minería. Dos mineros británicos desenterraron la mayor pepita de oro jamás registrada. Lo increíble es que estaba a solo 2,5 centímetros de la superficie.</span></p><p><span style=\"background-color: rgb(255, 255, 255); color: rgb(38, 38, 38);\">Desde ese día, han aparecido muchas otras pepitas igualmente&nbsp;espectaculares que también han captado la atención mundial. ¿Sabías que&nbsp;uno de los descubrimientos más impactantes de los últimos años fue hecho por un aficionado? Se topó con una pieza&nbsp;valorada en nada más y nada menos que 240.000 dólares australianos (unos $157.000).</span></p><p><br></p>', '2026-04-20 18:15:37', '2026-04-20 19:16:11', NULL, 4, 1),
(31, 'Encuentran a Cleopatra', '<p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Las historias y creencias sobre&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://www.cronista.com/informacion-gral/revelacion-historica-tras-miles-de-anos-encuentran-los-restos-de-la-cleopatra-de-latinoamerica-3852/\" rel=\"noopener noreferrer\" target=\"_blank\">Cleopatra</a></strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, la última faraona del antiguo Egipto, son de todo tipo y al día de hoy es una incógnita&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">el lugar en el que yace su tumba</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Recientemente, y tras una ardua investigación, se encontró&nbsp;</span><a href=\"https://www.cronista.com/informacion-gral/tension-mundial-el-ejercito-mas-fuerte-del-planeta-se-prepara-para-dominar-el-oceano-y-estrena-un-mega-submarino-2/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\">un templo submarino</a><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;que podría ser el sitio en el que fue enterrada la reina.</span></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Encontraron un templo que podría ser la tumba de Cleopatra</span></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">En una investigación encabezada por la exploradora de National Geographic&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Kathleen Martínez</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, que reconstruyó cada momento de la vida de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://www.cronista.com/informacion-gral/se-revelo-el-verdadero-rostro-de-cleopatra-en-una-antigua-estatua-que-cambia-la-historia-para-siempre-clone/\" rel=\"noopener noreferrer\" target=\"_blank\">Cleopatra</a></strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, se descubrieron&nbsp;</span><a href=\"https://www.cronista.com/informacion-gral/sin-excavar-ni-tocar-el-suelo-el-increible-descubrimiento-bajo-una-de-las-ciudades-mas-sagradas-de-egipto/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\">las ruinas</a><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;de lo que fue un puerto marítimo&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">hace más de 2000 años</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Este hallazgo se produjo en el&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Mar Mediterráneo</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, en la ciudad costera egipcia de Borg El Arab, en&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Taposiris Magna</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Tras el deslumbrante descubrimiento, el&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Ministerio de Turismo y Obras Arqueológicas de Egipto</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;expresó que este sitio no solo era un templo religioso, sino también un centro de intercambio marítimo de gran importancia.Para la arqueóloga&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Kathleen Martínez&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">esto refuerza su teoría sobra la faranoa y explicó que&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">“eso hace que el templo sea realmente importante</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, reunía todas las condiciones para&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">ser elegido como lugar de enterramiento de&nbsp;</strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://www.cronista.com/usa/ciencia-salud/se-revela-el-mayor-secreto-de-los-antiguos-egipcios-este-es-el-verdadero-rostro-de-cleopatra/\" rel=\"noopener noreferrer\" target=\"_blank\">Cleopatra</a></strong><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;junto a Marco Antonio</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">“, esbozó.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Con este nuevo paradigma, se pusieron en marcha nuevos&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">dispositivos de búsqueda</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;para develar, de una vez por todas, si&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">la tumba de Cleopatra</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;permanece en este lugar que había sido explorado en 2022.</span></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Cómo es el templo en el que podría estar la tumba de Cleopatra</span></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Años atrás, el equipo de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Kathleen Martínez</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;había anunciado el descubrimiento de tesoros y&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">piezas arqueológicas en Taposiris Magna</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;que habrían pertenecido a</span><a href=\"https://www.cronista.com/informacion-gral/se-revelo-el-verdadero-rostro-de-cleopatra-en-una-antigua-estatua-que-cambia-la-historia-para-siempre/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\">&nbsp;última reina egipcia</a><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Los mismos fueron hallados a 1300 metros de profundidad junto con&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">un túnel que tenía salida al mar</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">En el interior del túnel había vasijas, jarrones y artefactos hechos en cerámica, lo que llevó a la especialista a creer que \"</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">el puerto estuvo activo durante la época de Cleopatra</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;y antes, al comienzo de la dinastía\", expresó en un reporte de National Geographic.</span></p><h2><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Por qué creen que Cleopatra podría estar en Taposiris Magna</span></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">La arqueóloga e historiadora sobre la vida de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://www.cronista.com/informacion-gral/encuentran-a-cleopatra-el-descubrimiento-de-los-cientificos-que-cambia-para-siempre-la-historia-de-la-faraona/\" rel=\"noopener noreferrer\" target=\"_blank\">Cleopatra</a></strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, Kathleen Martínez, continúa al frente de la investigación y según sus propios estudios&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">“es cuestión de tiempo”</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;hasta hallar la tumba de la faraona del antiguo Egipto.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">En este sentido, y tras haber hallado el templo submarino en Taposiris Magna que fue ratificado por el por el&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Ministerio de Turismo y Obras Arqueológicas de Egipto</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, la especialista asegura que esto “es solo el comienzo de la tarea”.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Asimismo, la investigadora señaló: “Hasta ahora, hemos&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">descubierto más de 2600 objetos&nbsp;</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">en un lugar donde todo el mundo creía que&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">no había nada que encontrar\"</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, esbozó sobre el antiguo puerto marítimo.</span></p><p><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">“Hemos cambiado la historia de la zona hasta ahora</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, aunque no hayamos descubierto la tumba de Cleopatra.&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Seguiremos buscando en tierra y bajo el agua</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Este es el comienzo de una tarea enorme\", subrayó una de las investigadoras que más sigue de cerca el&nbsp;</span><a href=\"https://www.cronista.com/espana/actualidad-es/hallazgo-historico-en-jerusalen-descubren-una-antigua-moneda-de-oro-egipcia-de-hace-2200-anos/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\">misterio de Cleopatra</a><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;y el antiguo&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Egipto</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">.</span></p><p><br></p>', '2026-04-20 18:31:17', '2026-04-20 18:32:45', '1776720677_4a50cd99c39c40199995.jpg', 4, 1);
INSERT INTO `noticias` (`idNoticia`, `tituloNoticia`, `descripcionNoticia`, `fechaCreacionNoticia`, `fechaPublicacionNoticia`, `urlImagenNoticia`, `estadoNoticia`, `idAutorNoticia`) VALUES
(32, '¿Quién es Satoshi Nakamoto? Afirman haber descubierto al creador de Bitcoin', '<p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El foco de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\"><a href=\"https://www.perfil.com/noticias/internacional/el-criptografo-adam-back-desmintio-ser-natoshi-nakamoto-a31-al-new-york-times-y-pidio-que-se-mantenga-el-anonimato.phtml\" rel=\"noopener noreferrer\" target=\"_blank\">la sospecha recae sobre Adam Back</a></strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, criptógrafo británico y figura histórica del movimiento&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">cypherpunk</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. La pista que encendió las alarmas fue una escena del documental de HBO sobre Bitcoin, donde Back, interrogado sobre su&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">posible identidad como Satoshi</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, reacciona con tensión y pide que la conversación quede fuera de registro.No es una prueba, pero sí un gesto que, en&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">un universo obsesionado con el anonimato</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, resultó significativo para el ojo atento de Carreyrou. La investigación se apoya además en documentos revelados durante el juicio contra el australiano&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Craig Wright</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, quien en 2015 afirmó falsamente ser Satoshi.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Las evidencias son, sobre todo, de carácter técnico y lingüístico. El análisis de correos electrónicos, publicaciones en foros como&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Bitcointalk</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;y el propio&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">libro blanco de Bitcoin</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;revela patrones llamativos: una mezcla de inglés británico y estadounidense, coincidencias en errores gramaticales, uso de expresiones poco comunes y hasta similitudes en el uso de guiones. En ese terreno, Back sobresale por encima de otros candidatos, con cientos de coincidencias estilísticas con los textos atribuidos a&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Nakamoto</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Incluso el uso de términos técnicos y frases específicas parece alinearse con su perfil.</span></p><p><br></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Pero la conexión va más allá del lenguaje. Back fue el creador de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Hashcash</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, un sistema criptográfico que Satoshi utilizó como base para el mecanismo de&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">minería de Bitcoin</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Además, su trayectoria encaja con los pilares tecnológicos del proyecto:&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">sistemas distribuidos</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">,&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">redes descentralizadas</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;y programación en&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">C++</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">. Desde joven vinculado a la&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">criptografía</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, y formado en la&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Universidad de Exeter</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, Back desarrolló ideas que anticipaban con notable precisión los principios fundamentales de Bitcoin, mucho antes de su aparición en 2008.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El contexto ideológico también es clave. Tanto Back como Satoshi estaban profundamente influenciados por el movimiento&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">cypherpunk</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, una comunidad surgida en los años 90 que buscaba proteger la&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">privacidad individual</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;frente al avance del control estatal. Allí compartieron espacio figuras como&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Hal Finney</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, uno de los primeros colaboradores de Bitcoin y receptor de la primera transacción. La obsesión por crear un “</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">efectivo electrónico</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">” descentralizado, inmune a la censura y al rastreo, no era una ocurrencia aislada, sino el resultado de años de debate colectivo en listas de correo y foros especializados.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Sin embargo, el misterio sigue abierto. Otros nombres, como&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Nick Szabo</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;o&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Peter Todd</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, también han sido señalados en distintas investigaciones, mientras que indicios circunstanciales —como la sincronía entre la desaparición de Satoshi en 2011 y la posterior aparición pública de Back en el ecosistema— alimentan tanto la sospecha como la duda. Incluso el criptógrafo argentino&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Sergio Demian Lerner</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;aportó datos clave sobre la&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">fortuna de Nakamoto</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;que reconfiguraron el mapa de hipótesis.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Tal vez la respuesta nunca sea definitiva. Y quizás, como sostiene una parte de la&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">comunidad bitcoiner</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, no debería serlo. Porque más allá de quién haya sido Satoshi, el verdadero logro fue diseñar un sistema que no depende de su creador.</span></p><p><a href=\"https://www.perfil.com/noticias/opinion/la-acumulacion-no-para-y-bitcoin-enfrenta-un-momento-lleno-de-posibilidades-a40.phtml\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\">La acumulación no para y Bitcoin enfrenta un momento lleno de posibilidades</a></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">En ese sentido, revelar su identidad podría ser&nbsp;menos importante que preservar el mito: ese que permite que Bitcoin siga funcionando como lo que siempre prometió ser, una&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">red sin dueño</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">&nbsp;donde, en teoría, todos somos Satoshi.</span></p><p><br></p>', '2026-04-20 18:52:36', NULL, '1776723486_be2c49f65202cf7f0ff8.jpg', 2, 4),
(33, 'No somos 8 mil millones en el mundo', '<p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El debate se intensifica luego de que&nbsp;</span><a href=\"https://www.cronista.com/colombia/actualidad-co/hallazgo-del-siglo-desentierran-lingotes-y-monedas-de-oro-en-un-campo-sembrado-y-es-de-un-solo-pais/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\">investigadores&nbsp;</a><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">identificaran fallas en los métodos utilizados para medir la&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">densidad poblacional global</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, especialmente en regiones con menor acceso a sistemas de registro. Esto abre interrogantes sobre la precisión de los datos que han guiado decisiones durante décadas.</span></p><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Según especialistas, el conteo de habitantes nunca ha sido exacto. El demógrafo Jakub Bijak explicó a la BBC que “calcular el número de personas que hay en el planeta es una ciencia inexacta”, lo que refleja el nivel de incertidumbre que rodea estas cifras.</span></p><h2><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">El error en las zonas rurales que cambia todo el cálculo</strong></h2><p><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Un&nbsp;</span><a href=\"https://www.cronista.com/colombia/curiosidades/descubrimiento-del-siglo-encuentran-en-la-antartida-seres-marinos-jamas-antes-observados-que-podrian-reescribir-la-historia-de-la-biologia/\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"background-color: rgb(247, 247, 247); color: rgb(0, 114, 201);\">estudio&nbsp;</a><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">2025 publicado en&nbsp;</span><em style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">Nature</em><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, por investigadores de la Universidad de Aalto en Finlandia, evidenció que&nbsp;</span><strong style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">el mayor problema está en las áreas rurales</strong><span style=\"background-color: rgb(247, 247, 247); color: rgb(36, 36, 36);\">, donde millones de personas no han sido incluidas en los registros oficiales. Este vacío estadístico afecta de forma directa la comprensión del tamaño real de la población.</span></p><p><br></p>', '2026-04-20 19:30:09', '2026-04-20 19:31:57', '1776724209_2564e1153359bf5d880b.jpg', 4, 1);

